import{_ as t,o as a,c as s,ag as n}from"./chunks/framework.CanvC6-R.js";const u=JSON.parse('{"title":"Core Concepts","description":"","frontmatter":{},"headers":[],"relativePath":"language/core_concepts.md","filePath":"language/core_concepts.md"}'),o={name:"language/core_concepts.md"};function i(r,e,c,h,d,l){return a(),s("div",null,[...e[0]||(e[0]=[n('<h1 id="core-concepts" tabindex="-1">Core Concepts <a class="header-anchor" href="#core-concepts" aria-label="Permalink to &quot;Core Concepts&quot;">​</a></h1><p>This section defines the foundational ideas that underpin the Bliss language. Everything in the Language Reference builds on these concepts, so it is worth reading this section carefully before proceeding.</p><h2 id="what-s-covered" tabindex="-1">What&#39;s Covered <a class="header-anchor" href="#what-s-covered" aria-label="Permalink to &quot;What&#39;s Covered&quot;">​</a></h2><p><strong>Expressions and Statements</strong> — Bliss draws a strict distinction between expressions, which produce a value, and statements, which do not. Understanding this distinction is essential, as it governs what is valid in any given context throughout the language.</p><p><strong>Types</strong> — Bliss is statically typed. Every value has a type known at compile time, and types are always explicitly declared. This section defines the type system and the built-in types the language provides.</p><hr><p>These are not features — they are the rules the language is built on. When in doubt about why a construct behaves the way it does, the answer will almost always trace back to one of these two concepts.</p><hr><p>Short and purposeful. It sets expectations without repeating what the subsections will cover in detail. Ready for <code>expressions_and_statements.md</code>?</p>',9)])])}const g=t(o,[["render",i]]);export{u as __pageData,g as default};
